import psycopg2

DB_URL = "postgresql://postgres:postgres@db:5432/app_db"

descriptions_map = {
    "Мухомор": """<b>Червоний Мухомор (Amanita Muscaria) — мікродозинг для глибокого перезавантаження</b><br><br>Це повністю натуральна дієтична добавка, створена для тих, хто шукає внутрішнього балансу та спокою у сучасному ритмі життя. Наш продукт дбайливо зібраний в екологічно чистих лісах Карпат і пройшов сувору технологію сушіння при 35°C, що гарантує збереження всіх корисних мікроелементів.<br><br><b>Як працює мікродозинг мухомора:</b><br>• <b>Емоційна стабільність:</b> допомагає м'яко зняти напругу, тривожність та наслідки щоденного стресу.<br>• <b>Здоровий сон:</b> сприяє швидкому засинанню та глибокому, відновлювальному сну.<br>• <b>Ясність мислення:</b> допомагає позбутися «внутрішнього діалогу» та підвищити рівень усвідомленості.<br>• <b>Фізичний тонус:</b> знімає м'язові спазми та втому після важкого дня.<br><br><i>Цей продукт ідеально підходить для м'якої гармонізації стану без зміни свідомості.</i><br><br><u><i>*Не є лікарським засобом. Перед початком прийому рекомендується проконсультуватися з фахівцем.</i></u>""",

    "Їжовик": """<b>Їжовик гребінчастий (Lion's Mane) — ваш природний ноотроп та активатор мозку</b><br><br>Їжовик — це унікальний гриб, який століттями використовується для підтримки когнітивних функцій. Він стимулює вироблення фактору росту нервів (NGF), що буквально допомагає вашому мозку створювати нові нейронні зв'язки.<br><br><b>Головні переваги регулярного прийому:</b><br>• <b>Фокус та пам'ять:</b> значно підвищує концентрацію уваги, полегшує запам'ятовування великих обсягів інформації.<br>• <b>Продуктивність без виснаження:</b> дарує ясний розум і стабільну енергію без ефекту «відкату», як після кави або енергетиків.<br>• <b>Підтримка нервової системи:</b> захищає від емоційного вигорання та перевтоми.<br>• <b>Творчий потенціал:</b> сприяє креативному мисленню та швидкому вирішенню складних завдань.<br><br><i>100% органічний продукт для студентів, IT-спеціалістів, підприємців та всіх, хто працює інтелектуально.</i><br><br><u><i>*Не є лікарським засобом. Перед використанням рекомендується консультація фахівця.</i></u>""",

    "Кордицепс": """<b>Кордицепс (Cordyceps Militaris) — чиста енергія, витривалість та імунітет</b><br><br>Легендарний гриб, який став секретною зброєю професійних спортсменів та людей, що живуть на максимумі своїх можливостей. Кордицепс працює на клітинному рівні, покращуючи засвоєння кисню та стимулюючи вироблення АТФ — головного джерела енергії для нашого тіла.<br><br><b>Що ви отримаєте від прийому Кордицепсу:</b><br>• <b>Вибухова витривалість:</b> підвищує фізичну силу та допомагає легше переносити інтенсивні тренування або важку працю.<br>• <b>Міцний імунітет:</b> потужний природний антиоксидант, який захищає організм від зовнішніх подразників.<br>• <b>Швидке відновлення:</b> скорочує час регенерації м'язів після навантажень.<br>• <b>Життєвий тонус:</b> традиційно використовується для підтримки загального тонусу та лібідо.<br><br><i>Забудьте про втому — розкрийте свій фізичний потенціал на 100%.</i><br><br><u><i>*Не є лікарським засобом. Продукт призначений для збагачення раціону харчування.</i></u>"""
}

def run_update():
    conn = None
    try:
        conn = psycopg2.connect(DB_URL)
        cur = conn.cursor()
        for keyword, text in descriptions_map.items():
            cur.execute("UPDATE products SET description = %s WHERE name ILIKE %s", (text, f"%{keyword}%"))
            print(f"Оновлено: '{keyword}' - {cur.rowcount} шт.")
        conn.commit()
        cur.close()
        print("\n✅ МЕГА-ОПИСАНИЯ УСПЕШНО ЗАГРУЖЕНЫ В БАЗУ!")
    except Exception as e:
        print(f"Ошибка: {e}")
    finally:
        if conn: conn.close()

if __name__ == "__main__":
    run_update()
